/**
 * Adds another 2D grid point to this point.
 *
 * @param other The other point
 * @return this 2d grid point for chaining.
 */
public GridPoint2Mutant add(GridPoint2Mutant other) {
    x += other.x;
    y += other.y;
    return this;
}
